import{_ as i,o as e,c as l,a3 as s}from"./chunks/framework.gsMzR_Kb.js";const u=JSON.parse('{"title":"路径与命名规范","description":"统一英文路径、中文标题、别名与内容索引的命名规则。","frontmatter":{"title":"路径与命名规范","description":"统一英文路径、中文标题、别名与内容索引的命名规则。","category":"reference","aliases":["路径规范","命名规范","path conventions"]},"headers":[],"relativePath":"standards/path-conventions.md","filePath":"standards/path-conventions.md","lastUpdated":1777132262000}'),t={name:"standards/path-conventions.md"};function n(o,a,d,p,c,h){return e(),l("div",null,[...a[0]||(a[0]=[s(`<h1 id="路径与命名规范" tabindex="-1">路径与命名规范 <a class="header-anchor" href="#路径与命名规范" aria-label="Permalink to &quot;路径与命名规范&quot;">​</a></h1><p>这份规范专门解决一个问题：</p><blockquote><p>路径必须稳定、纯英文、可扩展；标题与理解则可以保持中文语境。</p></blockquote><h2 id="一、为什么统一用英文路径" tabindex="-1">一、为什么统一用英文路径 <a class="header-anchor" href="#一、为什么统一用英文路径" aria-label="Permalink to &quot;一、为什么统一用英文路径&quot;">​</a></h2><p>这样做的好处：</p><ul><li>避免构建、部署、外链和评论挂载中的中文路径兼容问题</li><li>让路径更稳定，更适合未来做 API、搜索、知识库切片</li><li>更适合程序化处理和批量生成</li></ul><h2 id="二、命名四件套" tabindex="-1">二、命名四件套 <a class="header-anchor" href="#二、命名四件套" aria-label="Permalink to &quot;二、命名四件套&quot;">​</a></h2><p>每个文档默认同时拥有四个标识：</p><ol><li><code>title</code>：中文标题</li><li><code>path</code>：英文访问路径</li><li><code>id</code>：稳定机器标识</li><li><code>aliases</code>：别名集合</li></ol><p>例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>title: 道德经导读</span></span>
<span class="line"><span>path: /daoism/texts/dao-de-jing/</span></span>
<span class="line"><span>id: dao-de-jing-guide</span></span>
<span class="line"><span>aliases: 道德经 / 老子 / dao de jing / ddj</span></span></code></pre></div><h2 id="三、slug-规则" tabindex="-1">三、slug 规则 <a class="header-anchor" href="#三、slug-规则" aria-label="Permalink to &quot;三、slug 规则&quot;">​</a></h2><p>路径 slug 默认遵循：</p><ul><li>只用小写英文字母、数字和连字符</li><li>不用空格</li><li>不用中文</li><li>不用拼音缩写乱跳层级</li><li>同级目录保持统一风格</li></ul><p>推荐：</p><ul><li><code>dao-de-jing</code></li><li><code>zhuang-zi</code></li><li><code>core-concepts</code></li><li><code>learning-method</code></li></ul><p>不推荐：</p><ul><li><code>DaoDeJing</code></li><li><code>道德经</code></li><li><code>dddj</code></li><li><code>study1</code></li></ul><h2 id="四、目录层级规则" tabindex="-1">四、目录层级规则 <a class="header-anchor" href="#四、目录层级规则" aria-label="Permalink to &quot;四、目录层级规则&quot;">​</a></h2><p>默认采用：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>section / module / topic / doc</span></span></code></pre></div><p>例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/daoism/texts/dao-de-jing/</span></span>
<span class="line"><span>/yijing/basics/learning-method</span></span></code></pre></div><h2 id="五、别名规则" tabindex="-1">五、别名规则 <a class="header-anchor" href="#五、别名规则" aria-label="Permalink to &quot;五、别名规则&quot;">​</a></h2><p>别名不是正式路径，而是帮助搜索与理解的辅助索引。</p><p>每篇文档建议准备这些别名：</p><ul><li>中文正式名</li><li>常见简称</li><li>常见拼写或拼音写法</li><li>必要时补英文解释名</li></ul><p>例如《道德经导读》可登记：</p><ul><li>道德经</li><li>老子</li><li>dao de jing</li><li>laozi</li><li>ddj</li></ul><h2 id="六、注册顺序" tabindex="-1">六、注册顺序 <a class="header-anchor" href="#六、注册顺序" aria-label="Permalink to &quot;六、注册顺序&quot;">​</a></h2><p>新增文档时，默认按这个顺序操作：</p><ol><li>先定 <code>section</code></li><li>再定 <code>module</code></li><li>再定英文 <code>slug</code></li><li>再定中文 <code>title</code></li><li>再补 <code>aliases</code></li><li>最后写正文</li></ol><h2 id="七、校验规则" tabindex="-1">七、校验规则 <a class="header-anchor" href="#七、校验规则" aria-label="Permalink to &quot;七、校验规则&quot;">​</a></h2><p>当前仓库已提供注册表校验：</p><ul><li>路径必须以 <code>/</code> 开头</li><li>路径必须是 ASCII slug</li><li><code>id</code> 不可重复</li><li>正式路径不可重复</li><li>别名不可重复</li><li>注册路径必须能找到对应文档</li></ul><p>执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:validate</span></span></code></pre></div><p>当前单一真相源：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docs/.vitepress/content-registry.mjs</span></span></code></pre></div><h2 id="八、当前建议" tabindex="-1">八、当前建议 <a class="header-anchor" href="#八、当前建议" aria-label="Permalink to &quot;八、当前建议&quot;">​</a></h2><p>如果未来要补六十四卦，建议沿用统一规则：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/yijing/hexagrams/qian/</span></span>
<span class="line"><span>/yijing/hexagrams/kun/</span></span>
<span class="line"><span>/yijing/hexagrams/zhun/</span></span></code></pre></div><p>并为每卦登记：</p><ul><li>中文卦名</li><li>卦序</li><li>常见别名</li><li>对应模板来源</li></ul>`,44)])])}const g=i(t,[["render",n]]);export{u as __pageData,g as default};
